func TestParseDatabaseLog(t *testing.T) {
	tests := []struct {
		log                database.Log
		rewardEpochID      int64
		startVotingRoundID uint32
		threshold          uint16
	}{
		{
			log:                log1,
			rewardEpochID:      2767,
			startVotingRoundID: 664080,
			threshold:          32765,
		},
		{
			log:                log2,
			rewardEpochID:      2766,
			startVotingRoundID: 663840,
			threshold:          32764,
		},
	}

	for i, test := range tests {
		event, err := policy.ParseSigningPolicyInitializedEvent(test.log)
		require.NoError(t, err)
		require.Equal(t, test.startVotingRoundID, event.StartVotingRoundId, fmt.Sprintf("error start voting round in test %d", i))
		require.Equal(t, big.NewInt(test.rewardEpochID), event.RewardEpochId)
	}
}

func TestNewSiginigPolicyLogs(t *testing.T) {
	tests := []struct {
		log         database.Log
		noOfVoters  int
		totalWeight uint16
		voter       string
		voterWeight uint16
		index       int
	}{
		{
			log:         log1,
			noOfVoters:  18,
			totalWeight: 65529,
			voter:       "5E5B3f46c8dEA1EC415Bd51047e66EE14A0F433C",
			voterWeight: 2,
			index:       16,
		},
		{
			log:         log2,
			noOfVoters:  17,
			totalWeight: 65528,
			voter:       "8fe15e1048f90bc028a60007c7d5b55d9d20de66",
			voterWeight: 9,
			index:       15,
		},
	}

	for i, test := range tests {
		event, err := policy.ParseSigningPolicyInitializedEvent(test.log)
		require.NoError(t, err)

		siginingPolicy := policy.NewSigningPolicy(event, nil)
		require.Equalf(t, test.totalWeight, siginingPolicy.Voters.TotalWeight, "error total weight test %d", i)
		require.Lenf(t, siginingPolicy.Voters.VoterDataMap, test.noOfVoters, "error number of voters test %d", i)

		voterData, ok := siginingPolicy.Voters.VoterDataMap[common.HexToAddress(test.voter)]
		require.Truef(t, ok, "error missing voter in test %d", i)
		require.Equalf(t, test.voterWeight, voterData.Weight, "error wrong weight test %d", i)
		require.Equalf(t, test.voterWeight, voterData.Weight, "error wrong index test %d", i)
	}
}

func TestStorage(t *testing.T) {
	storage := policy.NewStorage()

	event2, err := policy.ParseSigningPolicyInitializedEvent(log2)
	require.NoError(t, err)

	siginingPolicy2 := policy.NewSigningPolicy(event2, nil)

	err = storage.Add(siginingPolicy2)
	require.NoError(t, err)

	event1, err := policy.ParseSigningPolicyInitializedEvent(log1)
	require.NoError(t, err)

	siginingPolicy1 := policy.NewSigningPolicy(event1, nil)

	err = storage.Add(siginingPolicy1)
	require.NoError(t, err)

	policyFromStorage, ok := storage.ForVotingRound(663845)
	require.False(t, ok)
	require.Equal(t, uint32(2766), policyFromStorage.RewardEpochID)
	require.Equal(t, uint16(65528), policyFromStorage.Voters.TotalWeight)

	policyFromStorage, ok = storage.ForVotingRound(663445)
	require.False(t, ok)
	require.Nil(t, policyFromStorage)

	policyFromStorage, ok = storage.ForVotingRound(673445)
	require.True(t, ok)
	require.Equal(t, uint32(2767), policyFromStorage.RewardEpochID)
	require.Equal(t, uint16(65529), policyFromStorage.Voters.TotalWeight)

	removeEmpty := storage.RemoveBefore(12)
	require.Empty(t, removeEmpty)

	removeOne := storage.RemoveBefore(667080)
	require.Len(t, removeOne, 1)
}

func TestHash(t *testing.T) {
	// flare epoch 309
	// signingPolicyInitilized emitted in tx 0x86ffffab9fcadb3148b1e25dceecf3b37ad99d3b10008a53e527f7e4d6f73f36

	const rawHex = ""

	rawBytes, err := hex.DecodeString(rawHex)
	require.NoError(t, err)

	const expectedHashHex = "0x96986bfe5ffa787b6d33f4b16b3d40d5a46f38972c271771ddbe47fb142a0363"

	expectedHash := common.HexToHash(expectedHashHex)

	require.Equal(t, expectedHash[:], policy.Hash(rawBytes))
}
